import numpy as np

def dice_score(pred_mask, true_mask, smooth=1e-6):
    pred_flat = pred_mask.flatten()
    true_flat = true_mask.flatten()
    intersection = (pred_flat * true_flat).sum()
    return (2 * intersection + smooth) / (pred_flat.sum() + true_flat.sum() + smooth)

